def _safe_int(val, default=0):
    """Safely convert value to int, handling NaN/NaT/None."""
    if val is None:
        return default
    if isinstance(val, float) and (np.isnan(val) or np.isinf(val)):
        return default
    if pd.isna(val):
        return default
    try:
        return int(val)
    except (ValueError, TypeError):
        return default


def _safe_float(val, default=0.0):
    """Safely convert value to float, handling NaN/NaT/None."""
    if val is None:
        return default
    if pd.isna(val):
        return default
    try:
        result = float(val)
        if np.isnan(result) or np.isinf(result):
            return default
        return result
    except (ValueError, TypeError):
        return default

